// detailPrimaryAction picks the single state-aware "primary" action for the
// bottom bar. Mirrors TUI semantics:
//   - pending                          → start  (forward, primary)
//   - executing/verifying/reworking    → abort  (the only safe manual move;
//     done is intentionally hidden)
//   - done/aborted                     → rerun  (re-create + restart)
//
// Returns ("", "") when no primary action applies.
func detailPrimaryAction(task *orchestrator.Task, availableActions []string) (action, label string) {
	switch task.Status {
	case orchestrator.TaskStatusPending:
		for _, a := range availableActions {
			if a == "start" {
				return "start", "Start"
			}
		}
	case orchestrator.TaskStatusExecuting,
		orchestrator.TaskStatusVerifying,
		orchestrator.TaskStatusReworking:
		for _, a := range availableActions {
			if a == "abort" {
				return "abort", "Abort"
			}
		}
	case orchestrator.TaskStatusDone, orchestrator.TaskStatusAborted:
		return "rerun", "Rerun"
	}
	return "", ""
}

// actionPrimaryClass picks the visual variant for the primary bottom-bar
// button: blue for forward (start), red for destructive (abort), neutral
// for re-execute (rerun).
func actionPrimaryClass(action string) string {
	switch action {
	case "start":
		return "btn btn-primary"
	case "abort":
		return "btn btn-danger"
	default:
		return "btn btn-secondary"
	}
}

// editTabURLPath maps an activeTab name to the URL segment used by the
// corresponding edit route. Returns "" for tabs that are read-only.
func editTabURLPath(activeTab string) string {
	if activeTab == "description" {
		return activeTab
	}
	return ""
}

// DepsTreeRow is one row in the flattened dependency tree display:
// upstream (post-order DFS) → self → downstream (pre-order DFS).
// Prefix carries the tree connectors ("├─ ", "│  ", …) for the row.
type DepsTreeRow struct {
	Task   *orchestrator.Task
	IsSelf bool
	Prefix string
}

